def authenticate_tenant(f):
    """Authenticate tenant via API key."""
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        tenant_id = request.headers.get('X-Tenant-ID')
        if not api_key or not tenant_id:
            return jsonify({'error': 'Missing authentication credentials'}), 401
        expected_key = API_KEYS.get(tenant_id)
        if not expected_key or not hmac.compare_digest(
            hashlib.sha256(api_key.encode()).hexdigest(), expected_key
        ):
            return jsonify({'error': 'Invalid credentials'}), 403
        g.tenant_id = tenant_id
        return f(*args, **kwargs)
    return decorated


class SafeModelLoader:
    """
    Secure model loader that avoids arbitrary deserialization.
    
    Instead of using pickle (which allows arbitrary code execution),
    we support only safe, well-defined model formats:
    - ONNX (via onnxruntime)
    - PMML (via pypmml or similar)
    - JSON-based models (custom safe format with explicit schema validation)
    
    pickle.load / pickle.loads is NEVER used because any tenant could
    upload a crafted pickle file that executes arbitrary code on the server.
    """

    SAFE_FORMATS = {'onnx', 'json'}

    @staticmethod
    def validate_file_extension(filename):
        """Validate file has an allowed extension."""
        if '.' not in filename:
            return None
        ext = filename.rsplit('.', 1)[1].lower()
        if ext not in SafeModelLoader.SAFE_FORMATS:
            return None
        return ext

    @staticmethod
    def load_onnx_model(filepath):
        """Load an ONNX model using onnxruntime (safe deserialization)."""
        try:
            import onnxruntime as ort
            # onnxruntime uses protobuf deserialization, not arbitrary code execution
            session = ort.InferenceSession(filepath)
            return {
                'type': 'onnx',
                'session': session,
                'input_names': [inp.name for inp in session.get_inputs()],
                'output_names': [out.name for out in session.get_outputs()],
            }
        except ImportError:
            raise ValueError("ONNX runtime not installed. Install with: pip install onnxruntime")
        except Exception as e:
            raise ValueError(f"Failed to load ONNX model: {str(e)}")

    @staticmethod
    def load_json_model(filepath):
        """
        Load a JSON-defined model with strict schema validation.
        
        Supports simple model types defined in JSON:
        - Linear regression (weights + bias)
        - Decision thresholds
        - Lookup tables
        """
        with open(filepath, 'r') as f:
            try:
                model_def = json.load(f)
            except json.JSONDecodeError:
                raise ValueError("Invalid JSON file")

        # Strict schema validation
        if not isinstance(model_def, dict):
            raise ValueError("Model definition must be a JSON object")

        model_type = model_def.get('model_type')
        allowed_types = {'linear_regression', 'logistic_regression', 'threshold', 'lookup_table'}
        if model_type not in allowed_types:
            raise ValueError(f"Unsupported model type: {model_type}. Allowed: {allowed_types}")

        if model_type == 'linear_regression':
            return SafeModelLoader._load_linear_regression(model_def)
        elif model_type == 'logistic_regression':
            return SafeModelLoader._load_logistic_regression(model_def)
        elif model_type == 'threshold':
            return SafeModelLoader._load_threshold_model(model_def)
        elif model_type == 'lookup_table':
            return SafeModelLoader._load_lookup_table(model_def)

    @staticmethod
    def _validate_numeric_list(data, name, max_length=10000):
        """Validate that data is a list of numbers within bounds."""
        if not isinstance(data, list):
            raise ValueError(f"{name} must be a list")
        if len(data) > max_length:
            raise ValueError(f"{name} exceeds maximum length of {max_length}")
        for i, val in enumerate(data):
            if not isinstance(val, (int, float)):
                raise ValueError(f"{name}[{i}] is not a number")
            if not np.isfinite(val):
                raise ValueError(f"{name}[{i}] is not finite")
        return True

    @staticmethod
    def _load_linear_regression(model_def):
        """Load a linear regression model from validated JSON."""
        weights = model_def.get('weights')
        bias = model_def.get('bias')
        if weights is None or bias is None:
            raise ValueError("Linear regression requires 'weights' and 'bias'")
        SafeModelLoader._validate_numeric_list(weights, 'weights')
        if not isinstance(bias, (int, float)) or not np.isfinite(bias):
            raise ValueError("'bias' must be a finite number")

        weights_arr = np.array(weights, dtype=np.float64)
        return {
            'type': 'json',
            'model_type': 'linear_regression',
            'weights': weights_arr,
            'bias': float(bias),
            'predict': lambda x: float(np.dot(weights_arr, np.array(x)) + bias),
        }

    @staticmethod
    def _load_logistic_regression(model_def):
        """Load a logistic regression model from validated JSON."""
        weights = model_def.get('weights')
        bias = model_def.get('bias')
        if weights is None or bias is None:
            raise ValueError("Logistic regression requires 'weights' and 'bias'")
        SafeModelLoader._validate_numeric_list(weights, 'weights')
        if not isinstance(bias, (int, float)) or not np.isfinite(bias):
            raise ValueError("'bias' must be a finite number")

        weights_arr = np.array(weights, dtype=np.float64)

        def sigmoid(z):
            return 1.0 / (1.0 + np.exp(-np.clip(z, -500, 500)))

        return {
            'type': 'json',
            'model_type': 'logistic_regression',
            'weights': weights_arr,
            'bias': float(bias),
            'predict': lambda x: float(sigmoid(np.dot(weights_arr, np.array(x)) + bias)),
        }

    @staticmethod
    def _load_threshold_model(model_def):
        """Load a threshold model from validated JSON."""
        threshold = model_def.get('threshold')
        feature_index = model_def.get('feature_index', 0)
        if not isinstance(threshold, (int, float)) or not np.isfinite(threshold):
            raise ValueError("'threshold' must be a finite number")
        if not isinstance(feature_index, int) or feature_index < 0:
            raise ValueError("'feature_index' must be a non-negative integer")

        return {
            'type': 'json',
            'model_type': 'threshold',
            'threshold': float(threshold),
            'feature_index': feature_index,
            'predict': lambda x: 1.0 if x[feature_index] >= threshold else 0.0,
        }

    @staticmethod
    def _load_lookup_table(model_def):
        """Load a lookup table model from validated JSON."""
        table = model_def.get('table')
        default_value = model_def.get('default', 0.0)
        if not isinstance(table, dict):
            raise ValueError("'table' must be a dictionary")
        if len(table) > 100000:
            raise ValueError("Lookup table exceeds maximum size")
        # Validate all values are numeric
        for key, val in table.items():
            if not isinstance(val, (int, float)):
                raise ValueError(f"Table value for key '{key}' is not a number")

        return {
            'type': 'json',
            'model_type': 'lookup_table',
            'table': table,
            'default': default_value,
            'predict': lambda x: table.get(str(x), default_value),
        }

    @staticmethod
    def load_model(filepath, filename):
        """
        Safely load a model from a file.
        
        SECURITY: We explicitly do NOT support pickle, joblib, or any
        format that allows arbitrary code execution during deserialization.
        """
        ext = SafeModelLoader.validate_file_extension(filename)
        if ext is None:
            raise ValueError(
                f"Unsupported model format. Allowed formats: {SafeModelLoader.SAFE_FORMATS}"
            )

        if ext == 'onnx':
            return SafeModelLoader.load_onnx_model(filepath)
        elif ext == 'json':
            return SafeModelLoader.load_json_model(filepath)
        else:
            raise ValueError(f"Unsupported format: {ext}")


def get_tenant_model_dir(tenant_id):
    """Get isolated directory for tenant's models."""
    tenant_dir = os.path.join(app.config['UPLOAD_FOLDER'], secure_filename(tenant_id))
    os.makedirs(tenant_dir, exist_ok=True)
    return tenant_dir


@app.route('/api/v1/models/upload', methods=['POST'])
@authenticate_tenant
def upload_model():
    """
    Upload a model file for the authenticated tenant.
    
    Accepts ONNX and JSON model formats only.
    Pickle/joblib formats are explicitly rejected to prevent
    arbitrary code execution via deserialization attacks.
    """
    tenant_id = g.tenant_id

    if 'model_file' not in request.files:
        return jsonify({'error': 'No model file provided'}), 400

    file = request.files['model_file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400

    original_filename = secure_filename(file.filename)

    # Check file extension before saving
    ext = SafeModelLoader.validate_file_extension(original_filename)
    if ext is None:
        return jsonify({
            'error': f'Unsupported model format. Allowed formats: {SafeModelLoader.SAFE_FORMATS}. '
                     f'Pickle and joblib formats are not supported for security reasons.'
        }), 400

    model_id = str(uuid.uuid4())
    model_name = request.form.get('model_name', f'model_{model_id[:8]}')

    # Save to tenant-isolated directory
    tenant_dir = get_tenant_model_dir(tenant_id)
    save_filename = f"{model_id}.{ext}"
    filepath = os.path.join(tenant_dir, save_filename)
    file.save(filepath)

    # Attempt to load and validate the model
    try:
        model_info = SafeModelLoader.load_model(filepath, save_filename)
    except ValueError as e:
        # Clean up the invalid file
        os.remove(filepath)
        return jsonify({'error': f'Invalid model file: {str(e)}'}), 400
    except Exception as e:
        os.remove(filepath)
        return jsonify({'error': f'Failed to load model: {str(e)}'}), 400

    # Store model metadata
    if tenant_id not in tenant_models:
        tenant_models[tenant_id] = {}

    tenant_models[tenant_id][model_id] = {
        'model_id': model_id,
        'model_name': model_name,
        'filepath': filepath,
        'format': ext,
        'model_type': model_info.get('model_type', ext),
        'model': model_info,
    }

    return jsonify({
        'model_id': model_id,
        'model_name': model_name,
        'format': ext,
        'model_type': model_info.get('model_type', ext),
        'status': 'loaded',
    }), 201


@app.route('/api/v1/models/<model_id>/predict', methods=['POST'])
@authenticate_tenant
def predict(model_id):
    """Run inference using an uploaded model."""
    tenant_id = g.tenant_id

    # Tenant isolation: only access own models
    if tenant_id not in tenant_models or model_id not in tenant_models[tenant_id]:
        return jsonify({'error': 'Model not found'}), 404

    model_entry = tenant_models[tenant_id][model_id]
    model_info = model_entry['model']

    data = request.get_json()
    if not data or 'input' not in data:
        return jsonify({'error': 'Request must include "input" field'}), 400

    input_data = data['input']

    try:
        if model_info['type'] == 'onnx':
            result = _predict_onnx(model_info, input_data)
        elif model_info['type'] == 'json':
            result = _predict_json(model_info, input_data)
        else:
            return jsonify({'error': 'Unknown model type'}), 500

        return jsonify({
            'model_id': model_id,
            'prediction': result,
        })
    except Exception as e:
        return jsonify({'error': f'Prediction failed: {str(e)}'}), 400


def _predict_onnx(model_info, input_data):
    """Run prediction on an ONNX model."""
    session = model_info['session']
    input_names = model_info['input_names']

    # Prepare inputs
    feeds = {}
    if isinstance(input_data, dict):
        for name in input_names:
            if name in input_data:
                feeds[name] = np.array(input_data[name], dtype=np.float32)
    elif isinstance(input_data, list):
        if len(input_names) == 1:
            feeds[input_names[0]] = np.array(input_data, dtype=np.float32)
        else:
            raise ValueError("For multi-input models, provide a dict mapping input names to values")

    output_names = model_info['output_names']
    results = session.run(output_names, feeds)

    # Convert numpy arrays to lists for JSON serialization
    return {name: result.tolist() for name, result in zip(output_names, results)}


def _predict_json(model_info, input_data):
    """Run prediction on a JSON-defined model."""
    predict_fn = model_info.get('predict')
    if predict_fn is None:
        raise ValueError("Model does not have a predict function")

    # Validate input
    if isinstance(input_data, list):
        # Validate all elements are numbers
        for i, val in enumerate(input_data):
            if not isinstance(val, (int, float)):
                raise ValueError(f"Input[{i}] must be a number")
            if not np.isfinite(val):
                raise ValueError(f"Input[{i}] must be finite")
        return predict_fn(input_data)
    elif isinstance(input_data, (int, float, str)):
        return predict_fn(input_data)
    else:
        raise ValueError("Input must be a list of numbers, a number, or a string")


@app.route('/api/v1/models', methods=['GET'])
@authenticate_tenant
def list_models():
    """List all models for the authenticated tenant."""
    tenant_id = g.tenant_id
    models = tenant_models.get(tenant_id, {})

    model_list = []
    for model_id, entry in models.items():
        model_list.append({
            'model_id': entry['model_id'],
            'model_name': entry['model_name'],
            'format': entry['format'],
            'model_type': entry['model_type'],
        })

    return jsonify({'models': model_list})


@app.route('/api/v1/models/<model_id>', methods=['DELETE'])
@authenticate_tenant
def delete_model(model_id):
    """Delete a model for the authenticated tenant."""
    tenant_id = g.tenant_id

    if tenant_id not in tenant_models or model_id not in tenant_models[tenant_id]:
        return jsonify({'error': 'Model not found'}), 404

    entry = tenant_models[tenant_id].pop(model_id)

    # Clean up file
    filepath = entry.get('filepath')
    if filepath and os.path.exists(filepath):
        os.remove(filepath)

    return jsonify({'status': 'deleted', 'model_id': model_id})


